<span class="line"><span style="color:#CDD6F4;">        plugin</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">init</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#CDD6F4;"> ctx</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Plugin init failed&quot;</span><span style="color:#9399B2;">);</span></span>
